const getDocRef=(e,dk)=>{const n=e.ref?.replace(/\D/g,"")||"0001";const yr=n.slice(0,2);const num=n.slice(2).padStart(3,"0");const map={devis:"DV",convention:"CE",factAcompte:"FA",factInter:"FI",factSolde:"FS",recapMission:"RM",pvri:"PVRI",pvrf:"PVRF",avenant:"AV",rapportPeda:"RP",bulletinVersement:"BV"};return `${map[dk]||dk}${yr}${num}`;};
const getDocChain=e=>{const c=["devis","convention","factAcompte","recapMission"];if(e.hasPVRI)c.push("pvri");if(e.hasFactInter)c.push("factInter");if(e.hasAvenant)c.push("avenant");c.push("pvrf","factSolde","bulletinVersement","rapportPeda");return c;};
const fmt=n=>new Intl.NumberFormat("fr-FR",{style:"currency",currency:"EUR"}).format(n||0);
const pct=(a,b)=>b?Math.round(a/b*100):0;
const uid=()=>Date.now()+Math.floor(Math.random()*10000);
const calcTTC=(ht,r)=>(ht||0)*(1+(r||0)/100);
const totalJEH=p=>(p||[]).reduce((s,x)=>s+(Number(x.jeh)||0),0);
const totalPHT=p=>(p||[]).reduce((s,x)=>s+(Number(x.jeh)||0)*(Number(x.taux)||0),0);
const fmtDate=d=>d?new Date(d).toLocaleDateString("fr-FR",{day:"2-digit",month:"short",year:"numeric"}):"—";
const calcBV=(jeh,taux)=>{const brut=(jeh||0)*(taux||0),base=(jeh||0)*SMIC_H*8,assiette=base*4;return{brut,partJunior:assiette*.2993,partEtudiant:assiette*.17,totalCot:assiette*.2993+assiette*.17,net:brut-assiette*.17};};
const getStatut=e=>{if(e.bloquee)return"Bloquée";const d=e.docs||{};if(d.factSolde)return"Terminée";if(d.convention)return"En cours";if(d.devis)return"Convention";return"Brouillon";};
const stColor=s=>({Brouillon:C_.gray,Convention:C_.blue,"En cours":C_.orange,Terminée:C_.green,Bloquée:C_.red})[s]||C_.gray;
const initials=n=>n?.split(" ").map(w=>w[0]).join("").toUpperCase().slice(0,2)||"?";
const avColor=id=>["#6366F1","#EC4899","#14B8A6","#F59E0B","#8B5CF6","#EF4444","#06B6D4","#84CC16"][(id||0)%8];
const getSolde=e=>Math.max(0,100-(e.acompte||0)-(e.hasFactInter?(e.factInterPct||0):0));
const getFactMontant=(e,dk)=>{const ht=e.montantHT||0;if(dk==="factAcompte")return ht*(e.acompte||0)/100;if(dk==="factInter")return ht*(e.factInterPct||0)/100;if(dk==="factSolde")return ht*getSolde(e)/100;return ht;};
