const getMonth=d=>d?new Date(d).getMonth()+1:0;
const genClientInv=(etudes)=>{const inv=[];etudes.forEach(e=>{const d=e.docs||{};if(d.factAcompte||d.devis)inv.push({id:`${e.id}-ac`,ref:getDocRef(e,"factAcompte"),client:e.client,type:"Acompte",pct:`${e.acompte||30}%`,ht:getFactMontant(e,"factAcompte"),tva:e.tva,date:e.dateDebut||"",statut:d.factAcompte?"Émise":"Brouillon",payee:e.encaisse>0});if(e.hasFactInter&&(d.factInter||d.pvri))inv.push({id:`${e.id}-int`,ref:getDocRef(e,"factInter"),client:e.client,type:"Intermédiaire",pct:`${e.factInterPct||0}%`,ht:getFactMontant(e,"factInter"),tva:e.tva,date:"",statut:d.factInter?"Émise":"Brouillon",payee:false});if(d.pvrf||d.factSolde)inv.push({id:`${e.id}-sol`,ref:getDocRef(e,"factSolde"),client:e.client,type:"Solde",pct:`${getSolde(e)}%`,ht:getFactMontant(e,"factSolde"),tva:e.tva,date:"",statut:d.factSolde?"Émise":"Brouillon",payee:false});});return inv;};

